import{_ as a,o as l,c as i,ag as r}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"1997年巴菲特致股东信核心要点","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1997年/核心总结.md","filePath":"01_letters/1997年/核心总结.md"}'),o={name:"01_letters/1997年/核心总结.md"};function e(d,t,h,n,u,s){return l(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="_1997年巴菲特致股东信核心要点" tabindex="-1">1997年巴菲特致股东信核心要点 <a class="header-anchor" href="#_1997年巴菲特致股东信核心要点" aria-label="Permalink to &quot;1997年巴菲特致股东信核心要点&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净资产增长34.1%（80亿美元）</li><li>每股账面价值增长34.1%</li><li>33年复合增长率：24.1%</li></ul><h3 id="市场比较" tabindex="-1">市场比较 <a class="header-anchor" href="#市场比较" aria-label="Permalink to &quot;市场比较&quot;">​</a></h3><ul><li>标普500指数1997年上涨33.4%</li><li>伯克希尔&quot;几乎与市场同步&quot;</li><li><strong>结论</strong>：市场繁荣时难以超越**</li></ul><hr><h2 id="_1997年两大收购" tabindex="-1">1997年两大收购 <a class="header-anchor" href="#_1997年两大收购" aria-label="Permalink to &quot;1997年两大收购&quot;">​</a></h2><h3 id="_1-star家具" tabindex="-1">1. Star家具 <a class="header-anchor" href="#_1-star家具" aria-label="Permalink to &quot;1. Star家具&quot;">​</a></h3><ul><li><strong>地点</strong>：休斯顿</li><li><strong>创始人</strong>：Melvyn Wolff和Shirley Toomin</li><li><strong>历史</strong>：1924年开始，1962年由现任管理层接手</li><li><strong>规模</strong>：12家门店</li></ul><h3 id="_2-国际dq-international-dairy-queen" tabindex="-1">2. 国际DQ（International Dairy Queen） <a class="header-anchor" href="#_2-国际dq-international-dairy-queen" aria-label="Permalink to &quot;2. 国际DQ（International Dairy Queen）&quot;">​</a></h3><ul><li><strong>收购时间</strong>：1997年，1998年初完成</li><li><strong>门店数</strong>：5,792家DQ + 409家Orange Julius + 43家Karmelkorn</li><li><strong>CEO</strong>：Mike Sullivan</li></ul><hr><h2 id="市场波动观点" tabindex="-1">市场波动观点 <a class="header-anchor" href="#市场波动观点" aria-label="Permalink to &quot;市场波动观点&quot;">​</a></h2><h3 id="经典类比" tabindex="-1">经典类比 <a class="header-anchor" href="#经典类比" aria-label="Permalink to &quot;经典类比&quot;">​</a></h3><blockquote><p>&quot;如果你的余生都要吃汉堡，而且你不是牛肉生产者，你应该希望牛肉价格上涨还是下跌？&quot;</p></blockquote><blockquote><p>&quot;如果你不打算在近期卖出股票，你应该为股票市场上涨还是下跌感到高兴？&quot;</p></blockquote><h3 id="答案" tabindex="-1">答案 <a class="header-anchor" href="#答案" aria-label="Permalink to &quot;答案&quot;">​</a></h3><ul><li><strong>预期成为净买家</strong>：应该欢迎市场下跌</li><li><strong>伯克希尔97%股东是长期持有者</strong>：应该为市场下跌欢呼</li></ul><blockquote><p>&quot;微笑当你读到&#39;投资者因市场下跌而亏损&#39;的头条时。把它编辑为&#39;卖出者亏损——但投资者获利&#39;。&quot;</p></blockquote><hr><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><h3 id="浮存金数据-1997" tabindex="-1">浮存金数据（1997） <a class="header-anchor" href="#浮存金数据-1997" aria-label="Permalink to &quot;浮存金数据（1997）&quot;">​</a></h3><ul><li>浮存金：$7,093M</li><li>成本：<strong>负</strong>（盈利）</li><li>1967-1997年：31年中有23年成本为负</li></ul><h3 id="geico爆发式增长" tabindex="-1">GEICO爆发式增长 <a class="header-anchor" href="#geico爆发式增长" aria-label="Permalink to &quot;GEICO爆发式增长&quot;">​</a></h3><ul><li>自愿保单增长16%（历史新高）</li><li>2016年增长10%已是大新闻</li><li>5年数据： <ul><li>1993年：201万保单</li><li>1997年：295万保单（增长47%）</li></ul></li><li>利润分享贡献：26.9%（$71M）</li></ul><h3 id="超级巨灾保险" tabindex="-1">超级巨灾保险 <a class="header-anchor" href="#超级巨灾保险" aria-label="Permalink to &quot;超级巨灾保险&quot;">​</a></h3><ul><li>1997年&quot;非常幸运&quot;</li><li>&quot;最坏情况&quot;损失：$600M</li><li>价格战导致1998年业务量下降</li></ul><hr><h2 id="普通股持仓-1997年底" tabindex="-1">普通股持仓（1997年底） <a class="header-anchor" href="#普通股持仓-1997年底" aria-label="Permalink to &quot;普通股持仓（1997年底）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公司</th><th>持股</th><th>市值</th></tr></thead><tbody><tr><td>可口可乐</td><td>200M股</td><td>$13,338M</td></tr><tr><td>吉列</td><td>48M股</td><td>$4,821M</td></tr><tr><td>美国运通</td><td>49.5M股</td><td>$4,414M</td></tr><tr><td>房利美</td><td>64M股</td><td>$2,683M</td></tr><tr><td>富国银行</td><td>6.7M股</td><td>$2,271M</td></tr><tr><td>迪士尼</td><td>21.6M股</td><td>$2,135M</td></tr><tr><td>旅行者集团</td><td>23.7M股</td><td>$1,279M</td></tr></tbody></table><hr><h2 id="非传统投资" tabindex="-1">非传统投资 <a class="header-anchor" href="#非传统投资" aria-label="Permalink to &quot;非传统投资&quot;">​</a></h2><h3 id="_1-石油期货" tabindex="-1">1. 石油期货 <a class="header-anchor" href="#_1-石油期货" aria-label="Permalink to &quot;1. 石油期货&quot;">​</a></h3><ul><li>1994-95年建立4500万桶仓位</li><li>1997年底剩余1400万桶</li><li>利润：$61.9M（已实现）+ $11.6M（未实现）</li></ul><h3 id="_2-白银" tabindex="-1">2. 白银 <a class="header-anchor" href="#_2-白银" aria-label="Permalink to &quot;2. 白银&quot;">​</a></h3><ul><li>1997年购买1.112亿盎司</li><li>利润：$97.4M</li></ul><h3 id="_3-长期零息国债" tabindex="-1">3. 长期零息国债 <a class="header-anchor" href="#_3-长期零息国债" aria-label="Permalink to &quot;3. 长期零息国债&quot;">​</a></h3><ul><li>持仓：$46亿</li><li>1997年未实现利润：$598.8M</li></ul><hr><h2 id="可转换优先股" tabindex="-1">可转换优先股 <a class="header-anchor" href="#可转换优先股" aria-label="Permalink to &quot;可转换优先股&quot;">​</a></h2><h3 id="吉列" tabindex="-1">吉列 <a class="header-anchor" href="#吉列" aria-label="Permalink to &quot;吉列&quot;">​</a></h3><ul><li>1989年投资$600M</li><li>1997年价值：$4.8B（8倍！）</li></ul><h3 id="first-empire" tabindex="-1">First Empire <a class="header-anchor" href="#first-empire" aria-label="Permalink to &quot;First Empire&quot;">​</a></h3><ul><li>投资$40M</li><li>1997年价值：$236M</li></ul><h3 id="usair" tabindex="-1">USAir <a class="header-anchor" href="#usair" aria-label="Permalink to &quot;USAir&quot;">​</a></h3><ul><li>最终盈利！</li><li>CEO Stephen Wolf拯救了公司</li><li>&quot;如果我再做重大愚蠢决定，股东们知道该怎么做：给Wolf先生打电话。&quot;</li></ul><hr><h2 id="投资组合观点" tabindex="-1">投资组合观点 <a class="header-anchor" href="#投资组合观点" aria-label="Permalink to &quot;投资组合观点&quot;">​</a></h2><h3 id="指数基金vs主动投资" tabindex="-1">指数基金vs主动投资 <a class="header-anchor" href="#指数基金vs主动投资" aria-label="Permalink to &quot;指数基金vs主动投资&quot;">​</a></h3><blockquote><p>&quot;大多数投资者会发现，最佳方式是持有收取最低费用的指数基金。&quot;</p></blockquote><h3 id="个人投资建议" tabindex="-1">个人投资建议 <a class="header-anchor" href="#个人投资建议" aria-label="Permalink to &quot;个人投资建议&quot;">​</a></h3><ol><li><p>只需要两个课程：</p><ul><li>如何评估企业</li><li>如何思考市场价格</li></ul></li><li><p>购买规则：</p><ul><li>以合理价格购买优秀企业</li><li>只买能力圈内的企业</li><li>买有意义的数量</li><li>10年持有期</li></ul></li></ol><hr><h2 id="_1997年经典语录" tabindex="-1">1997年经典语录 <a class="header-anchor" href="#_1997年经典语录" aria-label="Permalink to &quot;1997年经典语录&quot;">​</a></h2><ol><li><p><strong>关于市场时机</strong>：</p><blockquote><p>&quot;试图时机购买股票是愚蠢的。&quot;</p></blockquote></li><li><p><strong>关于知识vs边界</strong>：</p><blockquote><p>&quot;能力圈的大小不重要；知道其边界才是关键的。&quot;</p></blockquote></li><li><p><strong>关于市场情绪</strong>：</p><blockquote><p>&quot;1970年代和1980年代的低价格使我们获得了巨大收益。&quot;</p></blockquote></li><li><p><strong>关于泡沫</strong>：</p><blockquote><p>&quot;在牛市中，必须避免骄傲的鸭子的错误。&quot;</p></blockquote></li><li><p><strong>关于延迟满足</strong>：</p><blockquote><p>&quot;现在商业&#39;投球&#39;只是勉强进入好球带。&quot;</p></blockquote></li></ol><hr><h2 id="_1997年启示" tabindex="-1">1997年启示 <a class="header-anchor" href="#_1997年启示" aria-label="Permalink to &quot;1997年启示&quot;">​</a></h2><ol><li><strong>市场无法预测</strong>：专注于企业价值</li><li><strong>长期视角</strong>：短期波动不影响长期成功</li><li><strong>避免杠杆</strong>：不用借来的钱投资</li><li><strong>等待好机会</strong>：不是每次都要挥杆</li><li><strong>税务效率</strong>：考虑税后收益</li></ol><hr><h2 id="_1993-1997年关键趋势总结" tabindex="-1">1993-1997年关键趋势总结 <a class="header-anchor" href="#_1993-1997年关键趋势总结" aria-label="Permalink to &quot;1993-1997年关键趋势总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>增长率</th><th>核心主题</th></tr></thead><tbody><tr><td>1993</td><td>14.3%</td><td>收购扩张</td></tr><tr><td>1994</td><td>13.9%</td><td>投资哲学深化</td></tr><tr><td>1995</td><td>45.0%</td><td>GEICO收购</td></tr><tr><td>1996</td><td>36.1%</td><td>&quot;必然企业&quot;概念</td></tr><tr><td>1997</td><td>34.1%</td><td>市场观点与税务</td></tr></tbody></table><hr><p>沃伦·E·巴菲特 1998年2月27日</p>',63)])])}const b=a(o,[["render",e]]);export{c as __pageData,b as default};
